```typescript
function solve(nums: number[]): number {
  const n = nums.length;
  if (n === 0) return -1;

  const maxNum = 1000000;
  const sieve = new Array(maxNum + 1).fill(true);
  sieve[0] = sieve[1] = false;
  for (let i = 2; i * i <= maxNum; i++) {
    if (sieve[i]) {
      for (let j = i * i; j <= maxNum; j += i) {
        sieve[j] = false;
      }
    }
  }

  const spf = new Array(maxNum + 1).fill(0);
  for (let i = 2; i <= maxNum; i++) {
    if (spf[i] === 0) {
      spf[i] = i;
      for (let j = i * 2; j <= maxNum; j += i) {
        if (spf[j] === 0) {
          spf[j] = i;
        }
      }
    }
  }

  const primeIndices = new Map<number, number[]>();
  for (let i = 0; i < n; i++) {
    const num = nums[i];
    if (num === 1) continue;
    const factors = new Set<number>();
    let x = num;
    while (x > 1) {
      const p = spf[x];
      factors.add(p);
      while (x % p === 0) {
        x /= p;
      }
    }
    for (const p of factors) {
      if (!primeIndices.has(p)) {
        primeIndices.set(p, []);
      }
      primeIndices.get(p)!.push(i);
    }
  }

  const visited = new Array(n).fill(false);
  const queue: [number, number][] = [[0, 0]];
  visited[0] = true;

  while (queue.length > 0) {
    const [idx, steps] = queue.shift()!;
    if (idx === n - 1) {
      return steps;
    }

    const nextIndices = [idx - 1, idx + 1];
    for (const next of nextIndices) {
      if (next >= 0 && next < n && !visited[next]) {
        visited[next] = true;
        queue.push([next, steps + 1]);
      }
    }

    const currentNum = nums[idx];
    if (sieve[currentNum]) {
      const primeList = primeIndices.get(currentNum);
      if (primeList) {
        for (const j of primeList) {
          if (j !== idx && !visited[j]) {
            visited[j] = true;
            queue.push([j, steps + 1]);
          }
        }
      }
    }
  }

  return -1;
}
